import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { createMint, getOrCreateAssociatedTokenAccount, mintTo } from '@solana/spl-token';

export default function DeployPage() {
  const { connection, wallets, addLog, setDeployedToken, addDebug } = useApp();
  const [tokenName, setTokenName] = useState('');
  const [tokenSymbol, setTokenSymbol] = useState('');
  const [decimals, setDecimals] = useState(9);
  const [supply, setSupply] = useState(1000000);
  const [isDeploying, setIsDeploying] = useState(false);
  const [selectedWallet, setSelectedWallet] = useState(0);

  const deployToken = async () => {
    addDebug('DEPLOY clicked');

    if (!connection) {
      addDebug('ERR: No connection');
      addLog('No connection', 'error');
      return;
    }

    if (wallets.length === 0) {
      addDebug('ERR: No wallets');
      addLog('Create wallet first!', 'error');
      return;
    }

    const wallet = wallets[selectedWallet];
    addDebug('Using: ' + wallet.publicKey.slice(0,8));

    try {
      setIsDeploying(true);
      addDebug('Starting createMint...');

      const mint = await createMint(
        connection,
        wallet.keypair,
        wallet.keypair.publicKey,
        wallet.keypair.publicKey,
        decimals
      );

      addDebug('Mint OK: ' + mint.toString().slice(0,8));
      addLog('Mint created!', 'success');

      addDebug('Creating token account...');
      const tokenAccount = await getOrCreateAssociatedTokenAccount(
        connection,
        wallet.keypair,
        mint,
        wallet.keypair.publicKey
      );

      addDebug('Account OK');

      if (supply > 0) {
        addDebug('Minting ' + supply + ' tokens...');

        const amount = BigInt(supply) * BigInt(Math.pow(10, decimals));
        addDebug('Amount: ' + amount.toString());

        await mintTo(
          connection,
          wallet.keypair,
          mint,
          tokenAccount.address,
          wallet.keypair.publicKey,
          amount
        );
        addDebug('Mint OK');
      }

      const tokenInfo = {
        mint: mint.toString(),
        name: tokenName || 'My Token',
        symbol: tokenSymbol || 'MTK',
        decimals,
        supply,
        owner: wallet.publicKey,
        tokenAccount: tokenAccount.address.toString()
      };

      setDeployedToken(tokenInfo);
      addDebug('SUCCESS!');
      addLog('Token deployed!', 'success');

    } catch (err) {
      addDebug('FAILED: ' + err.message.slice(0,40));
      addLog('Deploy failed: ' + err.message, 'error');
    } finally {
      setIsDeploying(false);
    }
  };

  return (
    <div style={{ padding: '10px' }}>
      <div style={{ background: 'rgba(0,0,0,0.3)', padding: '15px', borderRadius: '8px' }}>
        <div style={{ color: '#00f3ff', marginBottom: '15px', fontSize: '12px' }}>// DEPLOY TOKEN</div>

        {wallets.length === 0 ? (
          <p style={{ color: '#ff4444' }}>Create a wallet first!</p>
        ) : (
          <>
            <label style={{ color: '#666', fontSize: '12px' }}>Wallet</label>
            <select 
              value={selectedWallet} 
              onChange={e => setSelectedWallet(Number(e.target.value))}
              style={{ width: '100%', marginBottom: '12px', padding: '8px' }}
            >
              {wallets.map((w, i) => (
                <option key={w.publicKey} value={i}>
                  {w.name} ({w.publicKey.slice(0, 8)}...)
                </option>
              ))}
            </select>

            <label style={{ color: '#666', fontSize: '12px' }}>Name</label>
            <input value={tokenName} onChange={e => setTokenName(e.target.value)} placeholder="Token Name" style={{ width: '100%', marginBottom: '10px', padding: '8px' }} />

            <label style={{ color: '#666', fontSize: '12px' }}>Symbol</label>
            <input value={tokenSymbol} onChange={e => setTokenSymbol(e.target.value)} placeholder="SYMBOL" style={{ width: '100%', marginBottom: '10px', padding: '8px' }} />

            <label style={{ color: '#666', fontSize: '12px' }}>Decimals</label>
            <input type="number" value={decimals} onChange={e => setDecimals(Number(e.target.value))} style={{ width: '100%', marginBottom: '10px', padding: '8px' }} />

            <label style={{ color: '#666', fontSize: '12px' }}>Supply</label>
            <input type="number" value={supply} onChange={e => setSupply(Number(e.target.value))} style={{ width: '100%', marginBottom: '15px', padding: '8px' }} />

            <button 
              onClick={deployToken}
              disabled={isDeploying}
              style={{ 
                width: '100%', 
                padding: '12px', 
                background: isDeploying ? '#333' : '#00f3ff',
                border: 'none',
                borderRadius: '4px',
                fontWeight: 'bold'
              }}
            >
              {isDeploying ? 'Deploying...' : 'Deploy Token'}
            </button>
          </>
        )}
      </div>
    </div>
  );
}
